// Approval Executor v4 — Process & Route (clean rewrite)
//
// Reads approved tickets from HubSpot, emits per-action items with all data
// downstream nodes need to execute. Every approval is also logged to Decision
// Memory so Owl / Tally / etc can react on their next cycle (cross-agent
// handoff mechanism).

const now = new Date().toISOString();
const input = $input.first().json;
const results = input.results || [];
if (results.length === 0) return [];

const items = [];

for (const ticket of results) {
  const props = ticket.properties || {};
  const ticketId = ticket.id;
  const agentName = props.agent_name || 'Unknown';
  const recType = props.recommendation_type || '';
  const subject = props.subject || '';
  const content = props.content || '';
  const priority = props.hs_ticket_priority || 'LOW';
  const recDetailStr = props.recommendation_detail || '{}';
  const outcomeNotes = props.outcome_notes || '';

  let recDetail = {};
  try { recDetail = JSON.parse(recDetailStr); } catch (e) { recDetail = {}; }

  // Conditional approval detection
  const isConditional = outcomeNotes.includes('CONDITIONAL_APPROVE');
  const userInstructions = isConditional
    ? outcomeNotes.split('CONDITIONAL_APPROVE').pop().replace(/^[ —-]+/, '').trim()
    : '';

  // Base item shape — every downstream node reads these
  const item = {
    ticketId,
    agentName,
    recommendationType: recType,
    subject,
    content,
    priority,
    recDetail,
    isConditionalApproval: isConditional,
    userInstructions,
    action_type: 'auto_ack',
    executionNotes: 'Acknowledged.',
    executedAt: now,
    wpTitle: '', wpContent: '', wpSlug: '', wpStatus: 'draft',
    wpPatchPageId: 0, wpPatchType: 'pages', wpPatchTitle: '',
    wpPatchContent: '', wpPatchExcerpt: '', wpPatchAppendOnly: false,
    wpPatchSlug: '', wpPatchUrl: '',
    emailTo: '', emailCc: '', emailBcc: '', emailSubject: '', emailBodyHtml: '',
    // Cross-agent handoff payload (logged to Decision Memory below)
    handoffTo: '',   // 'Owl' | 'Tally' | 'Bee' | ''
    handoffPayload: {}
  };

  // ===== ROUTING TABLE =====

  // 1. Owl (Content Producer) -> wp_create draft
  if (agentName === 'Content Producer' || recType === 'Content Draft') {
    item.action_type = 'wp_create';
    item.wpTitle = (recDetail.pick && recDetail.pick.title) || subject.replace(/^\[Content[^\]]*\]\s*/i,'').trim();
    item.wpSlug = item.wpTitle.toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/^-|-$/g, '');
    const draft = recDetail.draft_preview || content;
    item.wpContent = isConditional ? `<!-- CONDITIONAL: ${userInstructions} -->\n${draft}` : draft;
    item.wpStatus = 'draft';
    item.executionNotes = `WP draft created: "${item.wpTitle}". Review on WordPress before publishing public.`;

  // 2. Bee (SEO Optimizer) -> wp_patch (title/excerpt/content)
  } else if (agentName === 'SEO Optimizer' || recType === 'Content Optimization') {
    const pageId = recDetail.wpId || recDetail.wp_page_id || recDetail.page_id || 0;
    const patch = recDetail.patch || {};
    const newTitle = patch.title || recDetail.proposed_title || '';
    const newExcerpt = patch.excerpt || recDetail.proposed_meta_description || '';
    let newContentChunk = '';
    if (patch.new_h2 || patch.new_section_body) {
      const h2 = patch.new_h2 ? `<h2>${patch.new_h2}</h2>\n` : '';
      const body = patch.new_section_body ? `<div>${patch.new_section_body.replace(/\n\n/g, '</p><p>').replace(/\n/g, '<br/>')}</div>` : '';
      newContentChunk = `\n\n<!-- Bee v3 SEO addition: ${recDetail.opportunity || ''} -->\n${h2}${body}`;
    }
    if (pageId) {
      item.action_type = 'wp_patch';
      item.wpPatchPageId = pageId;
      item.wpPatchType = recDetail.wp_type || 'pages';
      // PRODUCT_CAT_HANDLING_INJECTED — for WC categories, the editable field is `description`, not `content`
      if (item.wpPatchType === 'product_cat') {
        item.wpPatchDescription = recDetail.proposed_content || recDetail.patch?.new_section_body || recDetail.patch?.excerpt || '';
        item.wpPatchName = (recDetail.patch && recDetail.patch.title) || recDetail.proposed_title || '';
        // Yoast term meta — these render in <title>, <meta description>, OG tags.
        // Use the same title/excerpt from the patch (already length-validated by QA).
        item.wpPatchYoastTitle = (recDetail.patch && recDetail.patch.title) || recDetail.proposed_title || item.wpPatchName || '';
        item.wpPatchYoastMetaDesc = (recDetail.patch && recDetail.patch.excerpt) || recDetail.proposed_meta_description || '';
      }
      item.wpPatchTitle = newTitle;
      item.wpPatchExcerpt = newExcerpt;
      item.wpPatchContent = recDetail.proposed_content || newContentChunk;
      item.wpPatchAppendOnly = !!(newContentChunk && !recDetail.proposed_content);
      item.wpPatchSlug = recDetail.slug || '';
      item.wpPatchUrl = recDetail.url || '';
      item.executionNotes = `WP page ${pageId} updated by Bee (${recDetail.opportunity || 'SEO'}). Changed: ${[newTitle && 'title', newExcerpt && 'meta', newContentChunk && 'new section'].filter(Boolean).join(', ') || 'no fields'}.`;
    } else {
      item.action_type = 'auto_ack';
      item.executionNotes = 'Bee ticket approved but no wpId in recommendation_detail — no patch attempted.';
    }

  // 3. Eagle (UI/UX Performance) -> auto_ack (Eagle pre-patches itself) OR wp_patch (legacy)
  } else if (agentName === 'UI/UX Performance' || recType === 'Design Audit' || agentName === 'Agent 8 - UI/UX Performance' || agentName === 'UI/UX') {
    const at = recDetail.action_type || '';
    const pageId = recDetail.wp_page_id || recDetail.page_id || recDetail.wpId || 0;
    if (at === 'eagle_run_log') {
      item.action_type = 'auto_ack';
      item.executionNotes = `Eagle v3 run logged. Auto-fixes already applied: ${recDetail.auto_fixed_count || 0} across ${recDetail.pages_auto_fixed || 0} pages.`;
    } else if (pageId && recDetail.proposed_content) {
      item.action_type = 'wp_patch';
      item.wpPatchPageId = pageId;
      item.wpPatchType = recDetail.wp_type || 'pages';
      // PRODUCT_CAT_HANDLING_INJECTED — for WC categories, the editable field is `description`, not `content`
      if (item.wpPatchType === 'product_cat') {
        item.wpPatchDescription = recDetail.proposed_content || recDetail.patch?.new_section_body || recDetail.patch?.excerpt || '';
        item.wpPatchName = (recDetail.patch && recDetail.patch.title) || recDetail.proposed_title || '';
        // Yoast term meta — these render in <title>, <meta description>, OG tags.
        // Use the same title/excerpt from the patch (already length-validated by QA).
        item.wpPatchYoastTitle = (recDetail.patch && recDetail.patch.title) || recDetail.proposed_title || item.wpPatchName || '';
        item.wpPatchYoastMetaDesc = (recDetail.patch && recDetail.patch.excerpt) || recDetail.proposed_meta_description || '';
      }
      item.wpPatchContent = recDetail.proposed_content;
      item.executionNotes = `WP page ${pageId} updated with design fix.`;
    } else {
      item.action_type = 'auto_ack';
      item.executionNotes = 'Eagle ticket approved — logged as reviewed.';
    }

  // 4. Turtle (Content Decay Detector) -> HAND OFF to Owl for refresh draft
  } else if (agentName === 'Content Decay Detector' || recType === 'Content Refresh') {
    item.action_type = 'auto_ack';
    item.handoffTo = 'Owl';
    item.handoffPayload = {
      kind: 'refresh_url',
      url: recDetail.url || '',
      title: recDetail.title || '',
      click_drop_pct: recDetail.click_drop_pct,
      position_drop: recDetail.position_drop,
    };
    item.executionNotes = `Refresh queued for ${recDetail.url || 'URL'}. Owl will draft a refresh ticket on next cycle (handoff logged to Decision Memory).`;

  // 5. Hound (Keyword Discovery) -> HAND OFF to Tally for ad-group ingestion
  } else if (agentName === 'Keyword Discovery') {
    item.action_type = 'auto_ack';
    item.handoffTo = 'Tally';
    item.handoffPayload = {
      kind: 'new_keyword',
      keyword: recDetail.keyword || recDetail.term || '',
      pillar: recDetail.pillar || '',
      rationale: recDetail.rationale || '',
    };
    item.executionNotes = `Keyword "${recDetail.keyword || recDetail.term || '?'}" added to Tally's candidate queue (handoff logged to Decision Memory).`;

  // 6. Tally (SEM Manager) -> auto_ack (Maverick handles budgets, Paul handles non-budget manually)
  } else if (agentName === 'SEM Manager' || recType === 'Bid Adjustment') {
    item.action_type = 'auto_ack';
    item.executionNotes = `SEM approval logged (${recDetail.action || 'change'} on "${recDetail.keyword || '(keyword)'}"). Maverick will pick this up if it's a budget change. For non-budget changes, make manually in Google Ads.`;

  // 7. Spider (Backlink Builder) -> email_send to peer vendor
  } else if (agentName === 'Backlink Builder' || recType === 'Backlink Outreach') {
    const domain = recDetail.target_domain || '';
    const guessedTo = domain ? `info@${domain}` : '';
    const draftSubject = recDetail.subject_line || `Liftnow guest content - ${domain}`;
    const draftBody = recDetail.draft_email || '';
    item.action_type = guessedTo ? 'email_send' : 'auto_ack';
    item.emailTo = guessedTo;
    item.emailBcc = 'paulj@liftnow.com';
    item.emailSubject = draftSubject;
    const bodyHtml = draftBody.split(/\n\s*\n/).map(p => '<p>' + p.replace(/\n/g, '<br/>') + '</p>').join('');
    item.emailBodyHtml = bodyHtml + (isConditional ? `<hr/><p style="color:#666"><em>Conditional: ${userInstructions}</em></p>` : '');
    item.executionNotes = guessedTo
      ? `Outreach email sent to ${guessedTo} (BCC Paul). Domain: ${domain}.`
      : `Backlink ticket approved but no target_domain — no email sent.`;

  // 8. Beacon (LinkedIn Cadence) -> auto_ack (auto-post disabled, ticket IS the draft for manual paste)
  } else if (agentName === 'LinkedIn Cadence' || recType === 'LinkedIn Post') {
    item.action_type = 'auto_ack';
    item.executionNotes = `LinkedIn draft approved. Auto-post is currently disabled — copy the draft text from the ticket body and paste into LinkedIn manually. Re-enable auto-post once LinkedIn API is wired.`;

  // 9. Reed (Community Engagement / Reddit Reply) -> auto_ack (manual paste)
  } else if (agentName === 'Community Engagement' || recType === 'Reddit Reply') {
    item.action_type = 'auto_ack';
    item.executionNotes = `Reddit reply approved. Paste from u/liftnowpartnerships manually — Reddit closed self-service API access in 2026.`;

  // 10. Crow (Reddit Submissions) -> auto_ack (manual paste)
  } else if (agentName === 'Reddit Submissions' || recType === 'Reddit Submission') {
    item.action_type = 'auto_ack';
    item.executionNotes = `Reddit submission approved. Paste from u/liftnowpartnerships manually.`;

  // 11. Nox (Brand Listening) -> auto_ack
  } else if (agentName === 'Brand Listening' || recType === 'Brand Mention') {
    item.action_type = 'auto_ack';
    item.executionNotes = `Brand mention acknowledged. Logged for trend awareness.`;

  // 12. Cat (Competitor SERP Monitor) -> auto_ack
  } else if (agentName === 'Competitor SERP Monitor' || recType === 'Competitor Movement') {
    item.action_type = 'auto_ack';
    item.executionNotes = `Competitor movement acknowledged. Logged to Decision Memory for Cat's next-cycle context.`;

  // 13. Catch-all
  } else {
    item.action_type = 'auto_ack';
    item.executionNotes = `${agentName} report acknowledged.`;
  }

  items.push({ json: item });
}

// FINAL GUARD: downgrade email_send with empty recipient to auto_ack (defense in depth)
for (const it of items) {
  const j = it.json || it;
  if (j.action_type === 'email_send' && !(j.emailTo && String(j.emailTo).trim())) {
    j.action_type = 'auto_ack';
    j.executionNotes = (j.executionNotes || '') + ' [skipped: no recipient determined]';
  }
}

return items;

