// Post to LinkedIn — LinkedIn auto-post is DISABLED (per system policy).
// linkedin_post items pass through with executionNotes updated.

const items = $input.all();
return items.map(item => {
  const d = item.json || {};
  if (d.action === 'linkedin_post' || d.action_type === 'linkedin_post') {
    d.executionNotes = (d.executionNotes || '') + ' [LinkedIn auto-post is off — copy from ticket body and paste manually]';
    d.linkedInResult = 'manual_paste_required';
  }
  return { json: d };
});

// Mark Tickets Executed v4 — integrity check: don't claim Auto-Applied if downstream PATCH/POST returned an error.
// Read from Write Handoffs for the ticket list + executionNotes.
// Also peek at WP PATCH Page / Publish to WordPress / Send Email outputs to detect failed branches.

const processed = $('Write Handoffs').all().map(i => i.json);

// Collect error fingerprints from each executor branch
function branchHadError(nodeName, ticketId) {
  try {
    const items = $(nodeName).all().map(i => i.json);
    for (const it of items) {
      // WP REST error shape: {code: 'rest_cannot_*', message, data:{status: 4xx}}
      // SMTP failure: typically wouldn't return a body, would error out
      if (it && it.code && typeof it.code === 'string' && /^rest_/.test(it.code)) {
        return { failed: true, reason: it.code + ': ' + (it.message || '').slice(0, 200) };
      }
      // Generic error envelope
      if (it && it.data && it.data.status && it.data.status >= 400) {
        return { failed: true, reason: 'http ' + it.data.status + ': ' + (it.message || '').slice(0, 200) };
      }
    }
  } catch (e) {}
  return { failed: false };
}

return processed
  .filter(item => item.ticketId && item.ticketId !== '0')
  .map(item => {
    // Check executor branch outputs for this item's action_type
    let integrityFail = null;
    if (item.action_type === 'wp_patch') {
      integrityFail = branchHadError('WP PATCH Page', item.ticketId);
      // For product_cat, also check the Yoast endpoint
      if (!integrityFail.failed && item.wpPatchType === 'product_cat') {
        const yoastFail = branchHadError('PATCH Yoast Term Meta', item.ticketId);
        if (yoastFail.failed) integrityFail = yoastFail;
      }
    } else if (item.action_type === 'wp_create') {
      integrityFail = branchHadError('Publish to WordPress', item.ticketId);
    }
    const failed = integrityFail && integrityFail.failed;
    return {
      json: {
        ticketId: item.ticketId,
        url: 'https://api.hubapi.com/crm/v3/objects/tickets/' + item.ticketId,
        body: {
          properties: {
            // If failed, send back to stage 1 (Pending Review) instead of Auto-Applied
            hs_pipeline_stage: failed ? '1' : '1363043699',
            outcome_notes: failed
              ? ('EXECUTION FAILED: ' + (integrityFail.reason || 'unknown') + ' | Original intent: ' + (item.executionNotes || '').slice(0, 1000)).slice(0, 4000)
              : (item.executionNotes || '').slice(0, 4000),
          }
        },
        action: item.action_type,
        handoffTo: item.handoffTo || '',
        integrityFail: failed,
        integrityReason: integrityFail && integrityFail.reason,
      }
    };
  });

// Dual-write handoffs: legacy outcome_notes marker (30-day transition) +
// new typed REST handoff to /api/agent-handoffs.
//
// Legacy marker stays — Owl/Tally still parse it from HubSpot outcome_notes today.
// New REST write is best-effort: errors are logged into executionNotes but DO NOT
// fail the chain (defense-in-depth so a Vercel outage can't break AE).
//
// AE item shape (from Process & Route):
//   ticketId, agentName (full role), handoffTo (nickname),
//   handoffPayload = { kind, ...other }

const NICKNAME_TO_ROLE = {
  'Owl': 'Content Producer',
  'Tally': 'SEM Manager',
  'Bee': 'SEO Optimizer',
  'Eagle': 'UI/UX Performance',
  'Spider': 'Backlink Builder',
  'Nox': 'Brand Listening',
  'Beacon': 'LinkedIn Cadence',
};

const HANDOFF_API = 'https://bid-iq-neon.vercel.app/api/agent-handoffs';
const HANDOFF_SECRET = 'LiftnowAgentTeam_kS9-bGq2_xVtN4mP';

const items = $input.all();

for (const it of items) {
  const j = it.json || {};
  if (!j.handoffTo) continue;

  // === 1. Legacy marker (kept for 30-day transition) ===
  const legacyPayload = JSON.stringify({to: j.handoffTo, payload: j.handoffPayload || {}});
  j.executionNotes = (j.executionNotes || '') + ` HANDOFF:${legacyPayload}`;

  // === 2. New typed handoff (best-effort POST) ===
  const toRole = NICKNAME_TO_ROLE[j.handoffTo] || j.handoffTo;
  const kind = (j.handoffPayload && j.handoffPayload.kind) || '';
  const sourceTicketId = String(j.ticketId || '').trim();
  const fromAgent = j.agentName || 'Unknown';

  if (!kind || !sourceTicketId) {
    j.executionNotes += ` [handoff REST skipped: missing ${!kind ? 'kind' : 'ticketId'}]`;
    continue;
  }

  try {
    const resp = await this.helpers.httpRequest({
      method: 'POST',
      url: HANDOFF_API,
      headers: {
        'Content-Type': 'application/json',
        'x-agent-secret': HANDOFF_SECRET,
      },
      body: {
        from_agent: fromAgent,
        to_agent: toRole,
        kind: kind,
        payload: j.handoffPayload || {},
        source_ticket_id: sourceTicketId,
      },
      json: true,
      timeout: 8000,
    });
    if (resp && resp.ok && resp.id) {
      j.handoffRestId = resp.id;
      j.handoffRestAction = resp.action || 'unknown';
      j.executionNotes += ` [handoff REST ok: id=${resp.id} ${resp.action || ''}]`;
    } else {
      j.executionNotes += ` [handoff REST non-OK: ${JSON.stringify(resp || {}).slice(0,120)}]`;
    }
  } catch (e) {
    j.executionNotes += ` [handoff REST error: ${String((e && e.message) || e).slice(0,120)}]`;
  }
}

return items;

